import React, { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { getProductSuggestions } from './services/geminiService';
import SearchBar from './components/SearchBar';
import ProductGrid from './components/ProductGrid';
import FAQ from './components/FAQ';

const App = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const { data: products, isLoading, error } = useQuery(
    ['productSuggestions', searchTerm],
    () => getProductSuggestions(searchTerm),
    {
      enabled: searchTerm.length > 0,
      refetchOnWindowFocus: false,
    }
  );

  const handleSearch = (term: string) => {
    setSearchTerm(term);
  };

  const GuideSection = () => {
    return (
      <section className="bg-white py-8 px-4 sm:px-6 lg:px-8">
        <div className="max-w-2xl mx-auto text-center">
          <h2 className="text-3xl font-bold text-organic-green-dark mb-3">
            Start Your Discovery
          </h2>
          <p className="text-organic-green text-lg">Try a search (we'll ensure it's organic)</p>
        </div>
        <div className="mt-8 grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3 max-w-7xl mx-auto">
          {/* Example prompts */}
          {/* Example prompts */}
          {/* Example prompts */}
          <div className="rounded-lg shadow-md p-4 bg-gray-50 flex flex-col justify-between hover:shadow-xl transition-shadow duration-300 ease-in-out">
            <div>
              <p className="text-lg font-semibold text-gray-800 mb-2">Red wine</p>
            </div>
          </div>
          <div className="rounded-lg shadow-md p-4 bg-gray-50 flex flex-col justify-between hover:shadow-xl transition-shadow duration-300 ease-in-out">
            <div>
              <p className="text-lg font-semibold text-gray-800 mb-2">Cotton baby onesies</p>
            </div>
          </div>
          <div className="rounded-lg shadow-md p-4 bg-gray-50 flex flex-col justify-between hover:shadow-xl transition-shadow duration-300 ease-in-out">
            <div>
              <p className="text-lg font-semibold text-gray-800 mb-2">Fair-trade coffee</p>
            </div>
          </div>
        </div>
      </section>
    );
  };

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col">
      <header className="bg-organic-green-light py-4 px-4 sm:px-6 lg:px-8">
        <h1 className="text-3xl font-bold text-white text-center">
          Your Organic Discovery
        </h1>
      </header>

      <main className="flex-grow">
        <SearchBar onSearch={handleSearch} />
        {isLoading && <p>Loading...</p>}
        {error && <p>Error: {JSON.stringify(error)}</p>}
        {products && <ProductGrid products={products} />}
        <GuideSection />
        <FAQ />
      </main>

      <footer className="bg-organic-green-dark text-white py-4 px-4 sm:px-6 lg:px-8 text-center">
        &copy; {new Date().getFullYear()} Organic Discovery. All rights reserved.
      </footer>
    </div>
  );
};

export default App;
```
